SELECT ts_aggr.state, ts_aggr.timestamp AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr.bs__elec_minus_gas * bs.weight) AS elec_minus_gas__baseline, sum(ts_aggr.up__elec_minus_gas * bs.weight) AS elec_minus_gas__upgrade FROM (SELECT ts_flat.timestamp AS timestamp, ts_flat.bldg_id AS bldg_id, ts_flat.state AS state, sum(ts_flat._v__elec_minus_gas) FILTER (WHERE ts_flat.upgrade = 0) AS bs__elec_minus_gas, sum(ts_flat._v__elec_minus_gas) FILTER (WHERE ts_flat.upgrade = 1) AS up__elec_minus_gas, count(*) FILTER (WHERE ts_flat.upgrade = 0) AS _inner_rows FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, date_trunc('month', date_add('second', -900, resstock_2024_amy2018_release_2_by_state_vu.timestamp)) AS timestamp, resstock_2024_amy2018_release_2_by_state_vu.state AS state, resstock_2024_amy2018_release_2_by_state_vu.upgrade AS upgrade, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" - resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS _v__elec_minus_gas FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (0, 1) AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' AND resstock_2024_amy2018_release_2_by_state_vu.bldg_id IN (SELECT bs.bldg_id FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.upgrade IN (1) AND bs.applicability = true GROUP BY bs.bldg_id HAVING count(distinct(bs.upgrade)) = 1)) AS ts_flat GROUP BY ts_flat.timestamp, ts_flat.bldg_id, ts_flat.state) AS ts_aggr JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_aggr.bldg_id AND bs.upgrade = 0 GROUP BY 1, 2 ORDER BY 1, 2